package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val intent = intent
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            handleSendIntent(intent)
        } else {
            Log.d(TAG, "No shared content found")
        }
        
        finish()
    }
    
    private fun handleSendIntent(intent: Intent) {
        val extras = intent.extras
        val type = intent.type
        
        when {
            type.startsWith("text/") -> {
                val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                val title = intent.getStringExtra(Intent.EXTRA_TITLE)
                processTextContent(text, title)
            }
            type.startsWith("image/") -> {
                val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                if (uri != null) {
                    processImageContent(uri)
                }
            }
            else -> {
                Log.d(TAG, "Unsupported content type: $type")
            }
        }
    }
    
    private fun processTextContent(text: String?, title: String?) {
        if (!text.isNullOrEmpty()) {
            Log.d(TAG, "Received text: $text")
            // Process the shared text content
        }
        if (!title.isNullOrEmpty()) {
            Log.d(TAG, "Received title: $title")
        }
    }
    
    private fun processImageContent(uri: Uri) {
        try {
            val bitmap = contentResolver.openInputStream(uri)?.use { inputStream ->
                android.graphics.BitmapFactory.decodeStream(inputStream)
            }
            
            if (bitmap != null) {
                Log.d(TAG, "Received image with dimensions: ${bitmap.width}x${bitmap.height}")
                // Process the shared image content
                saveImageToFile(bitmap)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing image", e)
        }
    }
    
    private fun saveImageToFile(bitmap: Bitmap): File {
        val fileName = "shared_image_${System.currentTimeMillis()}.png"
        val file = File(cacheDir, fileName)
        FileOutputStream(file).use { out ->
            bitmap.compress(Bitmap.CompressFormat.PNG, 100, out)
        }
        return file
    }
}